<?php
namespace Database\Seeders;
use App\Models\PostCategory;use App\Models\TourismPlace;use App\Models\User;use Illuminate\Database\Seeder;
class TourismPlaceSeeder extends Seeder{public function run():void{$admin=User::first();$cat=PostCategory::firstOrCreate(['slug'=>'gorgan-tourism'],['title'=>'گردشگری گرگان','is_active'=>true]);$places=['جنگل ناهارخوران','پارک جنگلی النگدره','بازار نعلبندان','کاخ‌موزه گرگان','بافت تاریخی گرگان','روستای زیارت','آبشار رنگو','تپه هزارپیچ'];foreach($places as $i=>$title){TourismPlace::updateOrCreate(['slug'=>'tourism-'.($i+1)],['title'=>$title,'short_description'=>'معرفی جاذبه گردشگری '.$title.' در گرگان.','description'=>'<p>'.$title.' از نقاط شاخص گردشگری گرگان است و برای نمایش بخش گردشگری سایت ثبت شده است.</p>','featured_image'=>'assets/img/asnaf-gorgan-default.jpg','gallery'=>array_fill(0,4,'assets/img/asnaf-gorgan-default.jpg'),'category_id'=>$cat->id,'address'=>'استان گلستان، شهرستان گرگان، '.$title,'map_url'=>'https://maps.google.com','latitude'=>36.84+$i/100,'longitude'=>54.43+$i/100,'phone'=>'01732220000','working_hours'=>'همه روزه از ۸ تا ۲۰','visit_price'=>'رایگان / طبق تعرفه محل','status'=>'published','published_at'=>now()->subDays($i),'created_by'=>$admin?->id,'approved_by'=>$admin?->id,'sort_order'=>$i+1,'is_active'=>true]);}}}
